{"filePath":"icecream/styles.css","content":"@import url('https://fonts.googleapis.com/css2?family=Comfortaa:wght@400;600;700&family=Pacifico&family=Playfair+Display:ital,wght@0,600;1,400&display=swap');

:root {
  --pastel-pink: #ffd3e8;
  --pastel-purple: #e0ceff;
  --pastel-blue: #d0f4de;
  --pastel-yellow: #fff2cc;
  --pastel-orange: #ffebd3;
  --cream: #fffdf9;
  --text-dark: #4a3e4d;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: 'Comfortaa', cursive, sans-serif;
  color: var(--text-dark);
  background: linear-gradient(-45deg, #ffd3e8, #e0ceff, #d0eef4, #ffebd3);
  background-size: 400% 400%;
  animation: dreamyGradient 15s ease infinite;
  overflow-x: hidden;
}

/* Custom Scrollbar */
::-webkit-scrollbar {
  width: 10px;
}
::-webkit-scrollbar-track {
  background: rgba(255, 253, 249, 0.5);
}
::-webkit-scrollbar-thumb {
  background: var(--pastel-pink);
  border-radius: 10px;
  border: 2px solid rgba(255, 253, 249, 0.8);
}

/* Animations */
@keyframes dreamyGradient {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

@keyframes float {
  0%, 100% { transform: translateY(0px) rotate(0deg); }
  50% { transform: translateY(-15px) rotate(3deg); }
}

@keyframes float-reverse {
  0%, 100% { transform: translateY(0px) rotate(0deg); }
  50% { transform: translateY(12px) rotate(-3deg); }
}

@keyframes sparkle {
  0%, 100% { opacity: 0; transform: scale(0.5); }
  50% { opacity: 1; transform: scale(1.2); }
}

@keyframes scoopFall {
  0% { transform: translateY(-200px) scaleY(1.3); opacity: 0; }
  60% { transform: translateY(10px) scaleY(0.9); opacity: 1; }
  80% { transform: translateY(-5px) scaleY(1.05); }
  100% { transform: translateY(0) scaleY(1); }
}

/* Glassmorphism Classes */
.glass-card {
  background: rgba(255, 255, 255, 0.45);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid rgba(255, 255, 255, 0.6);
  border-radius: 24px;
  box-shadow: 0 8px 32px 0 rgba(194, 142, 172, 0.15);
}

.glass-nav {
  background: rgba(255, 255, 255, 0.6);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border-bottom: 1px solid rgba(255, 255, 255, 0.4);
}

/* Utility / Decorative classes */
.font-dreamy-title {
  font-family: 'Playfair Display', serif;
  font-weight: 600;
}

.font-fancy {
  font-family: 'Pacifico', cursive;
}

.floating {
  animation: float 6s ease-in-out infinite;
}

.floating-delayed {
  animation: float-reverse 7s ease-in-out infinite;
}

/* Sparkles container */
#sparkle-container {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 999;
}

.sparkle-particle {
  position: absolute;
  background: radial-gradient(circle, #fff 10%, rgba(255,255,255,0) 80%);
  border-radius: 50%;
  animation: sparkle 1.5s ease-out forwards;
}

/* Scoop Stacker Game */
.scoop-base {
  width: 140px;
  height: 100px;
  border-radius: 50% 50% 35% 35%;
  position: relative;
  box-shadow: inset -10px -10px 15px rgba(0,0,0,0.1), 0 6px 12px rgba(0,0,0,0.05);
  animation: scoopFall 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
  margin-bottom: -55px;
  z-index: 10;
}

.scoop-drips {
  position: absolute;
  bottom: -10px;
  left: 10%;
  width: 80%;
  display: flex;
  justify-content: space-around;
}

.drip {
  width: 15px;
  height: 15px;
  border-radius: 50%;
  background: inherit;
}

.cone-svg {
  width: 160px;
  height: 200px;
  z-index: 5;
  filter: drop-shadow(0 10px 8px rgba(0,0,0,0.06));
}

.scoops-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-end;
  height: 380px;
  position: relative;
}

/* Flavor specific styles */
.flavor-lavender { background: #e8dbfc; }
.flavor-strawberry { background: #ffccd5; }
.flavor-mint { background: #c1f0db; }
.flavor-vanilla { background: #fffcf0; }
.flavor-mango { background: #ffe4a0; }
.flavor-blueberry { background: #c5dcff; }

/* Glowing shadows for buttons */
.dream-btn {
  background: linear-gradient(135deg, #ff9ebb, #c3a6ff);
  color: white;
  border-radius: 50px;
  box-shadow: 0 4px 15px rgba(255, 158, 187, 0.4);
  transition: all 0.3s ease;
}

.dream-btn:hover {
  transform: translateY(-3px) scale(1.03);
  box-shadow: 0 8px 25px rgba(195, 166, 255, 0.6);
}

.dream-btn-outline {
  border: 2px solid #ff9ebb;
  color: #ff7ea3;
  border-radius: 50px;
  transition: all 0.3s ease;
}

.dream-btn-outline:hover {
  background: rgba(255, 158, 187, 0.15);
  transform: translateY(-2px);
}
