{"content":"// Initialize Lucide icons
lucide.createIcons();

// --- SPARKLE PARTICLE SYSTEM ---
const sparkleContainer = document.getElementById('sparkle-container');

// Create a sparkle particle
function createSparkle(x, y, isLarge = false) {
  const particle = document.createElement('div');
  particle.className = 'sparkle-particle';

  // Custom sizes
  const size = isLarge ? Math.random() * 20 + 10 : Math.random() * 8 + 4;
  particle.style.width = `${size}px`;
  particle.style.height = `${size}px`;

  // Custom positions
  particle.style.left = `${x - size / 2}px`;
  particle.style.top = `${y - size / 2}px`;

  // Random pastels colors for sparkles
  const colors = ['#fff', '#ffd3e8', '#e0ceff', '#d0f4de', '#fff2cc'];
  const randomColor = colors[Math.floor(Math.random() * colors.length)];
  particle.style.background = `radial-gradient(circle, ${randomColor} 20%, rgba(255,255,255,0) 80%)`;

  // Add some random drift
  const driftX = (Math.random() - 0.5) * 60;
  const driftY = (Math.random() - 0.5) * 60 - 20;
  particle.style.setProperty('--drift-x', `${driftX}px`);
  particle.style.setProperty('--drift-y', `${driftY}px`);

  // Custom CSS inject for movement path
  particle.style.transform = 'scale(0.5)';
  particle.animate([
    { transform: 'scale(0.5) translate(0, 0)', opacity: 0 },
    { opacity: 1, offset: 0.2 },
    { transform: `scale(1.2) translate(${driftX}px, ${driftY}px)`, opacity: 0 }
  ], {
    duration: 1000 + Math.random() * 800,
    easing: 'cubic-bezier(0.1, 0.8, 0.3, 1)',
    fill: 'forwards'
  });

  sparkleContainer.appendChild(particle);

  // Remove after animation finished
  setTimeout(() => {
    particle.remove();
  }, 2000);
}

// Sparkles on hover
window.addEventListener('mousemove', (e) => {
  if (Math.random() < 0.12) { // Throttle density
    createSparkle(e.clientX, e.clientY);
  }
});

// Sparkles on click
window.addEventListener('click', (e) => {
  for (let i = 0; i < 12; i++) {
    createSparkle(e.clientX, e.clientY, true);
  }
});

// Autopilot slow floating sparkles
setInterval(() => {
  const x = Math.random() * window.innerWidth;
  const y = Math.random() * window.innerHeight;
  createSparkle(x, y);
}, 300);


// --- THE INTERACTIVE SCOOP STACKER GAME ---
const scoopsContainer = document.querySelector('.scoops-container');
const coneSvg = document.querySelector('.cone-container');
const recipeNameBanner = document.getElementById('recipe-name');

let scoops = []; // Stores flavor strings
const MAX_SCOOPS = 4;

const flavorData = {
  lavender: { name: 'Lavender Moon', class: 'flavor-lavender' },
  strawberry: { name: 'Strawberry Blush', class: 'flavor-strawberry' },
  mint: { name: 'Minty Magic', class: 'flavor-mint' },
  vanilla: { name: 'Sweet Vanilla', class: 'flavor-vanilla' },
  mango: { name: 'Mango Sunrise', class: 'flavor-mango' },
  blueberry: { name: 'Cosmic Berry', class: 'flavor-blueberry' }
};

// Generates magical names for specific flavor combinations
function getRecipeName() {
  if (scoops.length === 0) return '';
  if (scoops.length === 1) return `Single ${flavorData[scoops[0]].name}`;

  // Famous combos
  const counts = {};
  scoops.forEach(f => counts[f] = (counts[f] || 0) + 1);

  if (scoops.includes('lavender') && scoops.includes('blueberry') && scoops.includes('mint')) {
    return '⭐ Midnight Constellation Swirl';
  }
  if (scoops.includes('strawberry') && scoops.includes('mango') && scoops.includes('vanilla')) {
    return '🌈 Dreamy Sunset Paradise';
  }
  if (scoops.length === 4) {
    return '👑 High-Altitude Star Tower';
  }
  if (scoops.every(val => val === scoops[0])) {
    return `Infinite ${flavorData[scoops[0]].name} Castle`;
  }

  const endings = ['Dream', 'Wonder', 'Delight', 'Galaxy', 'Cloud', 'Symphony'];
  const randomEnding = endings[Math.floor((scoops.length * 13) % endings.length)];
  return `${flavorData[scoops[0]].name} ${randomEnding}`;
}

function updateStackerUI() {
  // Clear any existing HTML scoops in UI
  const existingScoopsUI = scoopsContainer.querySelectorAll('.scoop-base');
  existingScoopsUI.forEach(el => el.remove());

  // Render scoops on top of cone
  scoops.forEach((flavorKey, index) => {
    const data = flavorData[flavorKey];

    const scoopEl = document.createElement('div');
    scoopEl.className = `scoop-base ${data.class}`;
    scoopEl.style.zIndex = 10 + index;
    // Layering offset
    scoopEl.style.marginBottom = `${-50}px`;

    // Add drip design
    const dripsContainer = document.createElement('div');
    dripsContainer.className = 'scoops-drips';

    for (let i = 0; i < 3; i++) {
      const drip = document.createElement('div');
      drip.className = 'drip';
      dripsContainer.appendChild(drip);
    }

    scoopEl.appendChild(dripsContainer);

    // Insert scoop before the cone element in HTML
    scoopsContainer.insertBefore(scoopEl, coneSvg);
  });

  // Update magical recipe name
  if (scoops.length > 0) {
    recipeNameBanner.textContent = getRecipeName();
    recipeNameBanner.style.transform = 'translateX(-52%) scale(1)';
    recipeNameBanner.style.opacity = '1';
    recipeNameBanner.classList.remove('scale-0');
  } else {
    recipeNameBanner.classList.add('scale-0');
    recipeNameBanner.style.opacity = '0';
  }
}

function addScoop(flavor) {
  if (scoops.length >= MAX_SCOOPS) {
    // Sparkle alert
    for (let i = 0; i < 10; i++) {
      createSparkle(window.innerWidth / 2 + (Math.random() - 0.5) * 100, window.innerHeight / 2, true);
    }
    alert("Oh, beautiful wizard! Your cone is fully stacked with starlight! 🍦");
    return;
  }

  scoops.push(flavor);
  updateStackerUI();

  // Create local splash of sparkles over the stacker area
  const stackerRect = scoopsContainer.getBoundingClientRect();
  for (let i = 0; i < 8; i++) {
    createSparkle(stackerRect.left + stackerRect.width / 2 + (Math.random() - 0.5) * 150, stackerRect.top + 100, false);
  }
}

function clearScoops() {
  scoops = [];
  updateStackerUI();
}

function sparkleCone() {
  if (scoops.length === 0) {
    alert("Please add at least one magical scoop first!");
    return;
  }

  const stackerRect = scoopsContainer.getBoundingClientRect();
  // Big burst of sparkly stardust
  for (let i = 0; i < 35; i++) {
    setTimeout(() => {
      createSparkle(
        stackerRect.left + stackerRect.width / 2 + (Math.random() - 0.5) * 200, 
        stackerRect.top + 150 + (Math.random() - 0.5) * 150, 
        true
      );
    }, i * 20);
  }
}
